interface Notification {
    void send(String message, String recipient);
    boolean validate();
}

class NotificationFactory {
    private static final Map<String, Supplier<Notification>> registry = new HashMap<>();

    static { /* register known types */ }

    public static Notification create(String type) {
        return registry.get(type).get();
    }
}

class CompositeNotification implements Notification {
    private final List<Notification> channels;

    CompositeNotification(List<Notification> channels) {
        this.channels = channels;
    }

    void send(String msg, String recipient) {
        channels.forEach(ch -> ch.send(msg, recipient));
    }
}

// Factory creates composites too:
static Notification createMulti(List<String> types) {
    List<Notification> channels = types.stream()
        .map(NotificationFactory::create)
        .toList();
    return new CompositeNotification(channels);
}
